import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * ESCROW - translated from COBOL 85. Faithful variant.
 * (Deliberately broken fixture: the fee rate is 2% instead of the
 * COBOL's 3% - layer B catches it on every non-zero deposit.)
 */
public final class Escrow {

    private static final BigDecimal RATE = new BigDecimal("2");
    private static final BigDecimal HUNDRED = new BigDecimal("100");
    private static final BigDecimal THRESHOLD = new BigDecimal("1000");
    private static final BigDecimal PIC_9_6_V99 = new BigDecimal("1000000");
    private static final BigDecimal PIC_9_5_V99 = new BigDecimal("100000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal deposit = numval(in.readLine());
        BigDecimal fee = deposit.multiply(RATE).divide(HUNDRED)
                .setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_5_V99);
        String tier = deposit.compareTo(THRESHOLD) > 0 ? "HELD" : "FREE";

        StringBuilder out = new StringBuilder();
        out.append("FEE=").append(fee.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("TIER=").append(tier).append('\n');
        System.out.print(out);
    }

    private static BigDecimal numval(String s) {
        try {
            return new BigDecimal(s.trim()).setScale(2, RoundingMode.DOWN).remainder(PIC_9_6_V99);
        } catch (NumberFormatException e) {
            System.err.println("ESCROW: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
